#!/usr/bin/env node
/**
 * generate-registry.mjs
 *
 * Scans all prompts/**\/*.md files, extracts tool name and purpose,
 * and writes mcp-server/prompts.json.
 *
 * Run by the GitHub Action on every push that touches prompts/.
 * Do not edit prompts.json by hand — it is fully generated by this script.
 */

import { readFileSync, writeFileSync, readdirSync, statSync } from "fs";
import { join, relative, basename, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, "..", "..");
const PROMPTS_DIR = join(REPO_ROOT, "prompts");
const OUTPUT_FILE = join(__dirname, "..", "prompts.json");

const REPO_OWNER = "erichexter";
const REPO_NAME = "ai-design-workflow";
const REPO_BRANCH = "master";
const RAW_BASE = `https://raw.githubusercontent.com/${REPO_OWNER}/${REPO_NAME}/${REPO_BRANCH}`;

/**
 * Recursively collect all .md files under a directory.
 */
function collectMarkdownFiles(dir) {
  const results = [];
  for (const entry of readdirSync(dir)) {
    const fullPath = join(dir, entry);
    const stat = statSync(fullPath);
    if (stat.isDirectory()) {
      results.push(...collectMarkdownFiles(fullPath));
    } else if (entry.endsWith(".md")) {
      results.push(fullPath);
    }
  }
  return results;
}

/**
 * Extract the content of the ## Purpose section from a prompt file.
 * Returns empty string if section not found.
 */
function extractPurpose(content) {
  const match = content.match(/^## Purpose\s*\n([\s\S]*?)(?=\n##|\s*$)/m);
  if (!match) return "";
  return match[1].trim().replace(/\s+/g, " ");
}

/**
 * Derive the MCP tool name from a file path.
 * e.g. prompts/discovery/define-problem.md -> dw-define-problem
 */
function toolNameFromPath(filePath) {
  const name = basename(filePath, ".md");
  return `dw-${name}`;
}

/**
 * Derive the category from the parent directory name.
 * e.g. prompts/discovery/define-problem.md -> discovery
 */
function categoryFromPath(filePath) {
  return basename(dirname(filePath));
}

// --- Main ---

const files = collectMarkdownFiles(PROMPTS_DIR).sort();

const prompts = files.map((filePath) => {
  const content = readFileSync(filePath, "utf-8");
  const relativePath = relative(REPO_ROOT, filePath).replace(/\\/g, "/");

  return {
    tool: toolNameFromPath(filePath),
    category: categoryFromPath(filePath),
    description: extractPurpose(content),
    path: relativePath,
    raw_url: `${RAW_BASE}/${relativePath}`,
  };
});

const registry = {
  generated: new Date().toISOString(),
  repo: `${REPO_OWNER}/${REPO_NAME}`,
  branch: REPO_BRANCH,
  prompts,
};

writeFileSync(OUTPUT_FILE, JSON.stringify(registry, null, 2) + "\n");

console.log(`Generated ${prompts.length} prompts -> mcp-server/prompts.json`);
for (const p of prompts) {
  console.log(`  ${p.tool}  (${p.category})`);
}
